import AddOutlined from '@universe-design/icons-react/AddOutlined';
import { Divider, Space } from '../../..';
import React from 'react';
import { ExpandButton } from '.';

export default {
  title: 'Shared Components/ExpandButton', // 注意：这里需要修改成自己对应 Component name。
};

export const ExpandButtonDemo = () => {
  const [isExpanded, setIsExpanded] = React.useState(false);
  return (
    <>
      <Divider>一般状态</Divider>
      <Space>
        <ExpandButton isExpanded={isExpanded} onExpandChange={setIsExpanded} iconType="ExpandDownFilled" />
        <ExpandButton isExpanded={isExpanded} onExpandChange={setIsExpanded} iconType="DownBoldOutlined" />
        <ExpandButton loading={true} isExpanded={isExpanded} onExpandChange={setIsExpanded} />
        <ExpandButton
          loading={true}
          isExpanded={isExpanded}
          onExpandChange={setIsExpanded}
          iconType="DownBoldOutlined"
        />
      </Space>
      <Divider>禁用状态</Divider>
      <Space>
        <ExpandButton isExpanded={isExpanded} onExpandChange={setIsExpanded} iconType="ExpandDownFilled" disabled />
        <ExpandButton isExpanded={isExpanded} onExpandChange={setIsExpanded} iconType="DownBoldOutlined" disabled />
      </Space>
      <Divider>自定义 icon</Divider>
      <Space>
        <ExpandButton
          isExpanded={isExpanded}
          onExpandChange={setIsExpanded}
          icon={props => <AddOutlined style={{ transform: props.isExpanded ? '' : 'rotate(180deg)' }} />}
        />
        <ExpandButton
          isExpanded={isExpanded}
          onExpandChange={setIsExpanded}
          icon={props => <AddOutlined style={{ transform: props.isExpanded ? '' : 'rotate(180deg)' }} />}
          disabled
        />
        <ExpandButton
          isExpanded={isExpanded}
          onExpandChange={setIsExpanded}
          icon={props => <AddOutlined style={{ transform: props.isExpanded ? '' : 'rotate(180deg)' }} />}
          loading
        />
      </Space>
    </>
  );
};
